	@Test
	void createReadTxnWaitsForTxnManagerWriteLock(@TempDir File dataDir) throws Exception {
		try (TripleStore tripleStore = new TripleStore(dataDir, new LmdbStoreConfig("spoc,posc"), null)) {
			TxnManager txnManager = tripleStore.getTxnManager();
			long writeStamp = txnManager.lockManager().writeLock();
			try {
				CountDownLatch createAttempting = new CountDownLatch(1);
				CountDownLatch readTxnCreated = new CountDownLatch(1);
				AtomicReference<Throwable> readerFailure = new AtomicReference<>();

				Thread reader = new Thread(() -> {
					createAttempting.countDown();
					try (Txn ignored = txnManager.createReadTxn()) {
						readTxnCreated.countDown();
					} catch (Throwable throwable) {
						readerFailure.compareAndSet(null, throwable);
					}
				}, "lmdb-create-read-txn-lock-test-reader");

				reader.start();

				assertThat(createAttempting.await(10, TimeUnit.SECONDS)).isTrue();
				assertThat(readTxnCreated.await(200, TimeUnit.MILLISECONDS))
						.as("read txn creation must wait while a txn-manager write lock is active")
						.isFalse();

				txnManager.lockManager().unlockWrite(writeStamp);
				writeStamp = 0;

				reader.join(TimeUnit.SECONDS.toMillis(10));
				assertThat(reader.isAlive()).isFalse();
				assertThat(readerFailure.get()).isNull();
			} finally {
				if (writeStamp != 0) {
					txnManager.lockManager().unlockWrite(writeStamp);
				}
			}
		}
	}

